mapper.sql:
WHERE o.deleted=0

    AND (c.course_code LIKE CONCAT('%', #{query.keyword}, '%') OR c.course_name LIKE CONCAT('%', #{query.keyword}, '%') OR o.teacher_name LIKE CONCAT('%', #{query.keyword}, '%') OR o.classroom LIKE CONCAT('%', #{query.keyword}, '%'))

AND o.course_id=#{query.courseId}
AND o.teacher_id=#{query.teacherId}
AND o.academic_year=#{query.academicYear}
AND o.semester=#{query.semester}
AND o.offering_status=#{query.offeringStatus}

mapper.select:
SELECT  FROM teaching_course_offering o
INNER JOIN teaching_course c ON c.id=o.course_id AND c.deleted=0

ORDER BY o.create_time DESC, o.id DESC LIMIT #{query.offset}, #{query.limit}

SELECT  FROM teaching_course_offering o
INNER JOIN teaching_course c ON c.id=o.course_id AND c.deleted=0
WHERE o.deleted=0 AND c.status=1 AND o.offering_status='OPEN'
  AND (o.selection_start_time IS NULL OR o.selection_start_time <= NOW())
  AND (o.selection_end_time IS NULL OR o.selection_end_time >= NOW())

    AND (c.course_code LIKE CONCAT('%', #{keyword}, '%') OR c.course_name LIKE CONCAT('%', #{keyword}, '%') OR o.teacher_name LIKE CONCAT('%', #{keyword}, '%'))

AND c.course_type=#{courseType}
AND o.academic_year=#{academicYear}
AND o.semester=#{semester}
ORDER BY o.academic_year DESC, o.semester DESC, c.course_code ASC
